  1→/* 
  2→ * @file   BQ24297.c
  3→ * @brief This file manages the BQ24297 module
  4→ */
  5→#define LOG_LVL LOG_LEVEL_BQ24297
  6→
  7→#include "BQ24297.h"
  8→#include "Util/Logger.h"
  9→#include "services/UsbCdc/UsbCdc.h"
 10→#include "peripheral/gpio/plib_gpio.h"
 11→#include "semphr.h"
 12→
 13→//! Pointer to the BQ24297 device configuration data structure
 14→static tBQ24297Config *pConfigBQ24;
 15→//! Pointer to the BQ24297 device "Write Variables" data structure
 16→static tBQ24297WriteVars *pWriteVariables;
 17→//! Pointer to the data structure where the BQ24297 data is
 18→static tBQ24297Data *pData;
 19→//! Mutex to synchronize I2C access between PowerAndUITask and USBDeviceTask
 20→static SemaphoreHandle_t i2cMutex = NULL;
 21→
 22→/*! Function to read BQ24297 data by I2C communication
 23→ * @param[in] reg Register to read
 24→ */
 25→uint8_t BQ24297_Read_I2C(uint8_t reg);
 26→
 27→/*! Function to write BQ24297 data by I2C communication
 28→ * @param[in] reg Register to write
 29→ * @param[in] txData Data to write
 30→ * @return true if write succeeded, false on error
 31→ */
 32→bool BQ24297_Write_I2C(uint8_t reg, uint8_t txData);
 33→
 34→void BQ24297_InitHardware(                                                  
 35→                        tBQ24297Config *pConfigInit,                        
 36→                        tBQ24297WriteVars *pWriteInit,                      
 37→                        tBQ24297Data *pDataInit) {
 38→    pConfigBQ24 = pConfigInit;
 39→    pWriteVariables = pWriteInit;
 40→    pData = pDataInit;
 41→
 42→    // Create I2C mutex for cross-task synchronization
 43→    if (i2cMutex == NULL) {
 44→        i2cMutex = xSemaphoreCreateMutex();
 45→        if (i2cMutex == NULL) {
 46→            LOG_E("BQ24297_InitHardware: failed to create I2C mutex");
 47→            pData->initComplete = false;
 48→            return;
 49→        }
 50→    }
 51→
 52→    // Battery management initialization (hardware interface)
 53→
 54→    // ***Disable I2C calls*** as Harmony 2.06 doesn't have a working, 
 55→    // interrupt-safe implementation
 56→    // Open the I2C Driver for Master
 57→    pData->I2C_Handle = DRV_I2C_Open(                                       
 58→                        pConfigBQ24->I2C_Index,                             
 59→                        DRV_IO_INTENT_READWRITE|DRV_IO_INTENT_BLOCKING);
 60→
 61→    // Drive OTG LOW — DPDM will set 100mA (conservative).
 62→    // ManageIINLIM state machine overrides IINLIM via I2C after DPDM completes.
 63→    BATT_MAN_OTG_OutputEnable();
 64→    BATT_MAN_OTG_Clear();
 65→}
 66→
 67→void BQ24297_Config_Settings(void) {
 68→    // Temporary value to hold current register value
 69→    uint8_t reg = 0;
 70→    
 71→    LOG_D("BQ24297_Config_Settings: Starting initialization");
 72→    
 73→    // Read initial status to determine current power state
 74→    BQ24297_UpdateStatus();
 75→
 76→    // Read REG00 to preserve current limit settings
 77→    reg = BQ24297_Read_I2C(0x00);
 78→    
 79→    // Clear HIZ mode if set - it can cause power loss
 80→    if (reg & 0x80) {
 81→        LOG_D("BQ24297_Config_Settings: Clearing HIZ mode");
 82→    }
 83→
 84→    // Set input voltage limit to 3.88V (minimum): VINDPM = 0
 85→    // This gives maximum headroom before input voltage regulation kicks in
 86→    // REG00: [7]=0 (CLEAR HIZ), [6:3]=0000 (3.88V min), [2:0]=keep current limit
 87→    BQ24297_Write_I2C(0x00, reg & 0b00000111);  // This also clears HIZ bit
 88→
 89→    // Configure REG01 for charging mode
 90→    // REG01 bits:
 91→    // [7:6] = 01 (reset watchdog)
 92→    // [5] = 0 (OTG disable)
 93→    // [4] = 1 (CHARGE ENABLE)
 94→    // [3:1] = 000 (SYS_MIN = 3.0V)
 95→    // [0] = 1 (reserved)
 96→    
 97→    // Drive OTG LOW — DPDM sets 100mA (conservative), ManageIINLIM overrides via I2C
 98→    BATT_MAN_OTG_OutputEnable();
 99→    BATT_MAN_OTG_Clear();
100→
101→    // Configure for charge mode with SYS_MIN=3.0V to prevent BATFET disable
102→    BQ24297_Write_I2C(0x01, 0b01010001);  // Watchdog reset, OTG=0, CHG=1, SYS_MIN=3.0V
103→
104→    // Set fast charge to 2000mA - this should never need to be updated
105→    BQ24297_Write_I2C(0x02, 0b01100000);
106→    
107→    // REG03: Pre-charge and termination current
108→    // Set minimum termination current (128mA) to avoid premature termination
109→    // [7:5]=000 (128mA precharge), [4]=0 (reserved), [3:0]=0001 (128mA termination)
110→    BQ24297_Write_I2C(0x03, 0b00000001);
111→
112→    // REG04: Charge voltage and battery thresholds
113→    // [7:2]=100101 (4.096V), [1]=1 (3.0V battery low), [0]=0 (100mV recharge)
114→    // Set BATLOWV to 3.0V (higher threshold) to keep BATFET enabled longer
115→    BQ24297_Write_I2C(0x04, 0b10010110);
116→
117→    // REG05: Disable watchdog and maximize charge timer
118→    // [7]=1 (enable termination), [6]=0 (disable timer), [5:4]=00 (disable watchdog)
119→    // [3]=0 (normal), [2:1]=11 (20hr timer), [0]=0 (reserved)
120→    // CRITICAL: Watchdog disabled to prevent unexpected BATFET disable
121→    BQ24297_Write_I2C(0x05, 0b10001110);
122→    
123→    // REG06: Boost voltage and thermal regulation
124→    // [7:4]=0111 (4.998V boost), [3:2]=00 (reserved), [1:0]=11 (120C thermal limit)
125→    // Keep default boost voltage but set highest thermal limit
126→    BQ24297_Write_I2C(0x06, 0b01110011);
127→    
128→    // Ensure BATFET is enabled (REG07 bit 5 = 0)
129→    // Without BATFET, there's no path from battery to system
130→    reg = BQ24297_Read_I2C(0x07);
131→    if (reg & 0b00100000) {  // Check if bit 5 is set (BATFET disabled)
132→        reg = reg & 0b11011111;  // Clear bit 5 to enable BATFET
133→        BQ24297_Write_I2C(0x07, reg);
134→        LOG_D("BQ24297: BATFET re-enabled");
135→    }
136→
137→    // Read the current status
138→    BQ24297_UpdateStatus();
139→
140→    // Start with conservative 500mA IINLIM
141→    // BQ24297_ManageIINLIM() state machine will adjust based on USB enumeration
142→    BQ24297_SetIINLIM(ILim_500);
143→    pData->iinlimState = IINLIM_STATE_IDLE;
144→    pData->iinlimTimestamp = 0;
145→    pData->iinlimLastVbus = false;
146→
147→    // Update battery presence status (for reporting only)
148→    BQ24297_UpdateBatteryStatus();
149→
150→    // Charging is always enabled via REG01 configuration above.
151→    // The BQ24297 has built-in hardware protection for:
152→    // - Battery temperature (NTC monitoring)
153→    // - Overvoltage/overcurrent
154→    // - Battery presence detection
155→    // Let the hardware handle charging decisions autonomously.
156→
157→    // Mark initialization complete
158→    pData->initComplete = true;
159→    
160→    LOG_D("BQ24297_Config_Settings: Initialization complete");
161→}
162→
163→/*
164→ * Updates BQ24297 status by reading all registers via I2C.
165→ * Called at boot, and on-demand by ForceDPDM, DisableOTG,
166→ * IsBatteryPresent, and UpdateBatteryStatus.
167→ */
168→void BQ24297_UpdateStatus(void) {
169→
170→    uint8_t regData = 0;
171→    bool hasErrors = false;
172→
173→    // REG00: Input Source Control
174→    regData = BQ24297_Read_I2C(0x00);
175→    if (regData != 0xFF) {
176→        pData->status.hiZ = (bool) (regData & 0b10000000);
177→        pData->status.inLim = (uint8_t) (regData & 0b00000111);
178→    } else {
179→        hasErrors = true;
180→    }
181→
182→    // REG01: Power-On Configuration
183→    regData = BQ24297_Read_I2C(0x01);
184→    if (regData != 0xFF) {
185→        pData->status.otg = (bool) (regData & 0b00100000);
186→        pData->status.chgEn = (bool) (regData & 0b00010000);
187→    } else {
188→        hasErrors = true;
189→    }
190→
191→    // REG02: Charge Current Control
192→    regData = BQ24297_Read_I2C(0x02);
193→    if (regData != 0xFF) {
194→        pData->status.ichg = (uint8_t) (regData & 0b11111100) >> 2;
195→    } else {
196→        hasErrors = true;
197→    }
198→
199→    // REG07: Misc Operation Control
200→    regData = BQ24297_Read_I2C(0x07);
201→    if (regData != 0xFF) {
202→        pData->status.iinDet_Read = (bool) (regData & 0b10000000);
203→    } else {
204→        hasErrors = true;
205→    }
206→
207→    // REG08: System Status
208→    regData = BQ24297_Read_I2C(0x08);
209→    if (regData != 0xFF) {
210→        pData->status.vBusStat = (uint8_t) (regData & 0b11000000) >> 6;
211→        pData->status.chgStat = (uint8_t) (regData & 0b00110000) >> 4;
212→        pData->status.dpmStat = (bool) (regData & 0b00001000);
213→        pData->status.pgStat = (bool) (regData & 0b00000100);
214→        pData->status.thermStat = (bool) (regData & 0b00000010);
215→        pData->status.vsysStat = (bool) (regData & 0b00000001);
216→        
217→        // vsysStat = 1 means battery voltage < VSYSMIN (3.0V)
218→        // This is critical for power-up decisions
219→        // Only log status changes to reduce log spam
220→        static uint8_t lastReg08 = 0xFF;
221→        if (regData != lastReg08) {
222→            LOG_D("BQ24297: REG08=0x%02X vsysStat=%d (batt %s 3.0V) pgStat=%d vBusStat=%d", 
223→                  regData, pData->status.vsysStat, 
224→                  pData->status.vsysStat ? "<" : ">", 
225→                  pData->status.pgStat, pData->status.vBusStat);
226→                  
227→            // Extra logging when vsysStat indicates low battery
228→            if (pData->status.vsysStat) {
229→                LOG_D("BQ24297: Battery voltage < 3.0V (vsysStat=1)");
230→            }
231→            
232→            lastReg08 = regData;
233→        }
234→    } else {
235→        hasErrors = true;
236→    }
237→
238→    // REG09: Fault Status - Reading resets latched fault flags!
239→    // First read clears latched faults, second read gets current status
240→    regData = BQ24297_Read_I2C(0x09);
241→    if (regData != 0xFF) {
242→        regData = BQ24297_Read_I2C(0x09);
243→        if (regData != 0xFF) {
244→            pData->status.watchdog_fault = (bool) (regData & 0b10000000);
245→            pData->status.otg_fault = (bool) (regData & 0b01000000);
246→            pData->status.chgFault = (uint8_t) (regData & 0b00110000) >> 4;
247→            pData->status.bat_fault = (bool) (regData & 0b00001000);
248→            pData->status.ntcFault = (uint8_t) (regData & 0b00000011);
249→        }
250→    } else {
251→        hasErrors = true;
252→    }
253→    
254→    if (hasErrors) {
255→        LOG_E("BQ24297_UpdateStatus: I2C communication errors detected");
256→    }
257→    
258→    // Check for critical faults
259→    if (pData->status.bat_fault) {
260→        LOG_E("BQ24297: BATFET fault - battery disconnected from system!");
261→    }
262→}
263→
264→void BQ24297_ChargeEnable(bool chargeEnable) {
265→    // Temporary value to hold current register value
266→    uint8_t reg = 0;
267→
268→    reg = BQ24297_Read_I2C(0x01);
269→
270→    // OTG and Charge are mutually exclusive
271→    if (reg & 0x20) {
272→        return;  // OTG is enabled, cannot modify charge state
273→    }
274→
275→    if (pData->chargeAllowed && chargeEnable && pData->status.batPresent) {
276→        // Enable charging, preserve all bits except bit 4 (charge enable)
277→        reg = (reg & 0b11101111) | 0b00010000; // Clear bit 4, then set it
278→        BQ24297_Write_I2C(0x01, reg);
279→    } else {
280→        // Disable charging, preserve all bits except bit 4 (charge enable)
281→        reg = (reg & 0b11101111); // Just clear bit 4
282→        BQ24297_Write_I2C(0x01, reg);
283→    }
284→}
285→
286→void BQ24297_ForceDPDM(void) {
287→    uint8_t reg = 0;
288→    // WARNING: Forcing DPDM while connected via USB will disrupt USB comms
289→    // and may require physical cable replug. Only safe from wall charger or UART.
290→
291→    reg = BQ24297_Read_I2C(0x07);
292→    if (reg == 0xFF) {
293→        LOG_E("BQ24297_ForceDPDM: REG07 read failed");
294→        return;
295→    }
296→
297→    // Force DPDM detection — REG07 bit 7
298→    if (!BQ24297_Write_I2C(0x07, reg | 0x80)) {
299→        LOG_E("BQ24297_ForceDPDM: REG07 write failed");
300→        return;
301→    }
302→
303→    const TickType_t start = xTaskGetTickCount();
304→    const TickType_t timeoutTicks = pdMS_TO_TICKS(2000);
305→
306→    for (;;) {
307→        BQ24297_UpdateStatus();
308→
309→        if (!pData->status.iinDet_Read) {
310→            break;
311→        }
312→
313→        if ((xTaskGetTickCount() - start) > timeoutTicks) {
314→            LOG_E("BQ24297_ForceDPDM: timeout waiting for DPDM to complete");
315→            break;
316→        }
317→
318→        vTaskDelay(pdMS_TO_TICKS(50));
319→    }
320→}
321→
322→void BQ24297_AutoSetILim(void) {
323→    // Temporary value to hold current register value
324→    uint8_t reg0;
325→
326→    reg0 = BQ24297_Read_I2C(0x00);
327→    
328→    // Log if HIZ mode is detected during AutoSetILim
329→    if (reg0 & 0x80) {
330→        LOG_E("BQ24297_AutoSetILim: WARNING - HIZ mode detected (REG00=0x%02X)! Will be cleared.", reg0);
331→    }
332→
333→    //  Set system input current
334→    // CRITICAL: Never preserve HIZ bit (bit 7) when writing to REG00!
335→    // Use mask 0b01111000 instead of 0b11111000 to clear HIZ
336→    switch (pData->status.vBusStat) {
337→        case 0b00:
338→            // Unknown - assume it is a charger. Set IINLIM to 2000mA       
339→            //- maximum allowed on charger
340→            BQ24297_Write_I2C(0x00, 0b00000110 | (reg0 & 0b01111000));
341→            break;
342→        case 0b01:
343→            // NOTE: Originally set to 500mA for USB 2.0 compliance, but this
344→            // caused audible whining from the power supply. Using 2A instead.
345→            // Most modern USB ports can handle this, especially with enumeration.
346→            // Original 500mA setting:
347→            // BQ24297_Write_I2C(0x00, 0b00000010 | (reg0 & 0b01111000));
348→            BQ24297_Write_I2C(0x00, 0b00000110 | (reg0 & 0b01111000));
349→            break;
350→        case 0b10:
351→            // Unknown - assume it is a charger. Set IINLIM to 2000mA 
352→            //maximum allowed on charger
353→            BQ24297_Write_I2C(0x00, 0b00000110 | (reg0 & 0b01111000));
354→            break;
355→        default:
356→            break;
357→    }
358→}
359→
360→uint8_t BQ24297_Read_I2C(uint8_t reg) {
361→    uint8_t I2CData[1];
362→    uint8_t rxData = 0;
363→
364→    if (pData->I2C_Handle == DRV_HANDLE_INVALID) {
365→        LOG_E("BQ24297_Read_I2C: Invalid I2C handle");
366→        return 0xFF;
367→    }
368→
369→    if (i2cMutex != NULL) {
370→        xSemaphoreTake(i2cMutex, portMAX_DELAY);
371→    }
372→
373→    // Build data packet
374→    I2CData[0] = reg;
375→
376→    // Perform I2C transfer with error checking
377→    bool success = DRV_I2C_WriteReadTransfer(pData->I2C_Handle,
378→            pConfigBQ24->I2C_Address,
379→            I2CData,
380→            1,
381→            &rxData,
382→            1);
383→
384→    if (i2cMutex != NULL) {
385→        xSemaphoreGive(i2cMutex);
386→    }
387→
388→    if (!success) {
389→        LOG_E("BQ24297_Read_I2C: Failed to read register 0x%02X", reg);
390→        return 0xFF;
391→    }
392→
393→    return rxData;
394→}
395→
396→bool BQ24297_Write_I2C(uint8_t reg, uint8_t txData) {
397→    uint8_t I2CData[2];
398→
399→    if (pData->I2C_Handle == DRV_HANDLE_INVALID) {
400→        LOG_E("BQ24297_Write_I2C: Invalid I2C handle");
401→        return false;
402→    }
403→
404→    if (i2cMutex != NULL) {
405→        xSemaphoreTake(i2cMutex, portMAX_DELAY);
406→    }
407→
408→    // Build data packet
409→    I2CData[0] = reg;
410→    I2CData[1] = txData;
411→
412→    // Write to selected register with error checking
413→    bool success = DRV_I2C_WriteTransfer(
414→                    pData->I2C_Handle,
415→                    pConfigBQ24->I2C_Address,
416→                    I2CData,
417→                    2);
418→
419→    if (i2cMutex != NULL) {
420→        xSemaphoreGive(i2cMutex);
421→    }
422→
423→    if (!success) {
424→        LOG_E("BQ24297_Write_I2C: Failed to write 0x%02X to register 0x%02X", txData, reg);
425→    }
426→
427→    return success;
428→}
429→
430→bool BQ24297_SetIINLIM(uint8_t iinlimCode) {
431→    // REG00 IINLIM is 3-bit field (bits 2:0), valid range 0-7 per datasheet Table 9-2
432→    if (iinlimCode > ILim_3000) return false;
433→    uint8_t reg = BQ24297_Read_I2C(0x00);
434→    if (reg == 0xFF) return false;
435→    // Clear HIZ (bit 7) and IINLIM (bits 2:0), preserve VINDPM (bits 6:3)
436→    reg = (reg & 0b01111000) | (iinlimCode & 0x07);
437→    bool success = BQ24297_Write_I2C(0x00, reg);
438→    if (!success) {
439→        LOG_E("BQ24297_SetIINLIM: Failed to write IINLIM code %u", iinlimCode);
440→    }
441→    return success;
442→}
443→
444→void BQ24297_ManageIINLIM(bool vbusPresent) {
445→    TickType_t now = xTaskGetTickCount();
446→
447→    switch (pData->iinlimState) {
448→        case IINLIM_STATE_IDLE:
449→            if (vbusPresent && !pData->iinlimLastVbus) {
450→                // Rising edge — VBUS just appeared
451→                LOG_D("IINLIM: VBUS appeared, entering WAIT_DPDM");
452→                pData->iinlimTimestamp = now;
453→                pData->iinlimState = IINLIM_STATE_WAIT_DPDM;
454→            }
455→            break;
456→
457→        case IINLIM_STATE_WAIT_DPDM:
458→            if (!vbusPresent) {
459→                LOG_D("IINLIM: VBUS lost during WAIT_DPDM, returning to IDLE");
460→                pData->iinlimState = IINLIM_STATE_IDLE;
461→                break;
462→            }
463→            {
464→                TickType_t elapsed = now - pData->iinlimTimestamp;
465→
466→                // Wait at least 1s after VBUS before acting on DPDM result
467→                // to ensure BQ24297 hardware has fully settled
468→                if (elapsed < pdMS_TO_TICKS(1000)) {
469→                    break;
470→                }
471→
472→                // Check REG07 bit 7 for DPDM in progress
473→                uint8_t reg07 = BQ24297_Read_I2C(0x07);
474→                bool dpdmDone = (reg07 != 0xFF) && !(reg07 & 0x80);
475→                bool timeout = elapsed >= pdMS_TO_TICKS(3000);
476→
477→                if (dpdmDone) {
478→                    // DPDM finished — safe to set IINLIM, hardware won't overwrite
479→                    if (BQ24297_SetIINLIM(ILim_500)) {
480→                        LOG_D("IINLIM: DPDM done after %lu ms, set 500mA, entering WAIT_USB",
481→                              (unsigned long)(elapsed * portTICK_PERIOD_MS));
482→                        pData->iinlimTimestamp = now;
483→                        pData->iinlimState = IINLIM_STATE_WAIT_USB;
484→                    } else {
485→                        LOG_E("IINLIM: Failed to set 500mA, retrying next cycle");
486→                    }
487→                } else if (timeout) {
488→                    // DPDM stuck after 3s — set IINLIM anyway
489→                    LOG_E("IINLIM: DPDM not complete after 3s (REG07=0x%02X), forcing 500mA",
490→                          reg07);
491→                    if (BQ24297_SetIINLIM(ILim_500)) {
492→                        pData->iinlimTimestamp = now;
493→                        pData->iinlimState = IINLIM_STATE_WAIT_USB;
494→                    } else {
495→                        LOG_E("IINLIM: Failed to set 500mA on timeout, retrying next cycle");
496→                    }
497→                }
498→            }
499→            break;
500→
501→        case IINLIM_STATE_WAIT_USB:
502→            if (!vbusPresent) {
503→                BQ24297_SetIINLIM(ILim_500);
504→                LOG_D("IINLIM: VBUS lost during WAIT_USB, reset to 500mA");
505→                pData->iinlimState = IINLIM_STATE_IDLE;
506→                break;
507→            }
508→            if ((now - pData->iinlimTimestamp) >= pdMS_TO_TICKS(2000)) {
509→                if (UsbCdc_IsConfigured()) {
510→                    // USB host enumerated — keep 500mA (USB-spec safe)
511→                    LOG_D("IINLIM: USB configured, keeping 500mA");
512→                    pData->iinlimState = IINLIM_STATE_SETTLED;
513→                } else {
514→                    // No USB enumeration — wall charger, bump to 2000mA
515→                    if (BQ24297_SetIINLIM(ILim_2000)) {
516→                        LOG_D("IINLIM: No USB config, set 2000mA (wall charger)");
517→                        pData->iinlimState = IINLIM_STATE_SETTLED;
518→                    } else {
519→                        LOG_E("IINLIM: Failed to set 2000mA, retrying next cycle");
520→                    }
521→                }
522→            }
523→            break;
524→
525→        case IINLIM_STATE_SETTLED:
526→            if (!vbusPresent) {
527→                BQ24297_SetIINLIM(ILim_500);
528→                LOG_D("IINLIM: VBUS lost, reset to 500mA");
529→                pData->iinlimState = IINLIM_STATE_IDLE;
530→            }
531→            break;
532→
533→        default:
534→            pData->iinlimState = IINLIM_STATE_IDLE;
535→            break;
536→    }
537→
538→    pData->iinlimLastVbus = vbusPresent;
539→}
540→
541→void BQ24297_EnableOTG(void) {
542→    // Read REG08 for safety checks
543→    uint8_t reg08 = BQ24297_Read_I2C(0x08);
544→    bool pgStat = (reg08 >> 2) & 0x01;
545→    uint8_t vbusStat = (reg08 >> 6) & 0x03;
546→    
547→    // Clear HIZ mode if active
548→    uint8_t reg00 = BQ24297_Read_I2C(0x00);
549→    if (reg00 & 0x80) {
550→        reg00 &= 0x7F;  // Clear bit 7 (HIZ)
551→        BQ24297_Write_I2C(0x00, reg00);
552→        vTaskDelay(5 / portTICK_PERIOD_MS);
553→    }
554→    
555→    // Cannot enable OTG if external power is present
556→    if (pgStat) {
557→        return;
558→    }
559→    
560→    // Check if OTG is already active
561→    if (vbusStat == 0x03) {
562→        uint8_t reg01 = BQ24297_Read_I2C(0x01);
563→        if (reg01 & 0x20) {
564→            pData->status.otg = true;
565→            pData->status.chgEn = false;
566→            return;
567→        }
568→    }
569→    
570→    // Set OTG GPIO HIGH to enable boost mode
571→    BATT_MAN_OTG_OutputEnable();
572→    BATT_MAN_OTG_Set();
573→    
574→    // Read current REG01 value
575→    uint8_t reg01 = BQ24297_Read_I2C(0x01);
576→    if (reg01 == 0xFF) {
577→        return;
578→    }
579→    
580→    // Configure REG01 for OTG mode
581→    // Bit 5 = 1 (OTG enable), Bit 4 = 0 (charge disable), Bit 6 = 1 (watchdog reset)
582→    reg01 = (reg01 & 0x0F) | 0x60;
583→    
584→    // Write with retry logic
585→    bool success = false;
586→    for (int retry = 0; retry < 3; retry++) {
587→        if (BQ24297_Write_I2C(0x01, reg01)) {
588→            vTaskDelay(5 / portTICK_PERIOD_MS);
589→            
590→            // Verify write
591→            uint8_t readback = BQ24297_Read_I2C(0x01);
592→            if ((readback & 0x30) == 0x20) {  // Check OTG=1, CHG=0
593→                success = true;
594→                break;
595→            }
596→        }
597→        vTaskDelay(10 / portTICK_PERIOD_MS);
598→    }
599→    
600→    if (!success) {
601→        BATT_MAN_OTG_Clear();  // Clear GPIO on failure
602→    }
603→    
604→    // Update status
605→    pData->status.otg = success;
606→    pData->status.chgEn = false;
607→}
608→
609→void BQ24297_DisableOTG(bool enableCharging) {
610→    // Clear HIZ mode if active
611→    uint8_t reg00 = BQ24297_Read_I2C(0x00);
612→    if (reg00 != 0xFF && (reg00 & 0x80)) {
613→        reg00 &= 0x7F;  // Clear bit 7
614→        BQ24297_Write_I2C(0x00, reg00);
615→        vTaskDelay(2 / portTICK_PERIOD_MS);
616→    }
617→    
618→    // Set GPIO LOW to disable OTG
619→    BATT_MAN_OTG_OutputEnable();
620→    BATT_MAN_OTG_Clear();
621→    vTaskDelay(2 / portTICK_PERIOD_MS);
622→    
623→    // Read and modify REG01
624→    uint8_t reg = BQ24297_Read_I2C(0x01);
625→    if (reg == 0xFF) {
626→        pData->status.otg = false;
627→        return;
628→    }
629→    
630→    // Clear OTG bit (bit 5), set watchdog reset (bit 6)
631→    // Keep SYS_MIN at 3.0V (bits 3:1 = 000)
632→    reg = (reg & 0b11010001) | 0b01000001;
633→    
634→    // Set charge enable if requested
635→    if (enableCharging) {
636→        reg |= 0b00010000;
637→    }
638→    
639→    // Write the new value
640→    if (!BQ24297_Write_I2C(0x01, reg)) {
641→        return;
642→    }
643→    
644→    // Check for HIZ mode after REG01 write
645→    vTaskDelay(5 / portTICK_PERIOD_MS);
646→    reg00 = BQ24297_Read_I2C(0x00);
647→    if (reg00 != 0xFF && (reg00 & 0x80)) {
648→        reg00 &= 0x7F;
649→        BQ24297_Write_I2C(0x00, reg00);
650→    }
651→    
652→    // Update local status
653→    pData->status.otg = false;
654→    pData->status.chgEn = (reg & 0x10) ? true : false;
655→    
656→    // Give the BQ24297 time to perform input detection
657→    vTaskDelay(50 / portTICK_PERIOD_MS);
658→    
659→    // Update status to reflect changes
660→    BQ24297_UpdateStatus();
661→}
662→
663→bool BQ24297_IsOTGEnabled(void) {
664→    uint8_t reg = BQ24297_Read_I2C(0x01);
665→    return (reg & 0b00100000) != 0;
666→}
667→
668→bool BQ24297_IsChargingEnabled(void) {
669→    uint8_t reg = BQ24297_Read_I2C(0x01);
670→    return (reg & 0b00010000) != 0;
671→}
672→
673→bool BQ24297_IsBatteryPresent(void) {
674→    // Battery detection logic:
675→    // 1. If thermistor reads COLD (open circuit), battery is disconnected
676→    // 2. If thermistor reads HOT, it's stuck low (shorted) - battery may be present but charging unsafe
677→    // 3. Normal thermistor AND voltage > 3.0V indicates battery present
678→    
679→    // Update status to get latest NTC and voltage readings
680→    BQ24297_UpdateStatus();
681→    
682→    // NTC_FAULT_COLD (2) = thermistor open = no battery
683→    if (pData->status.ntcFault == NTC_FAULT_COLD) {
684→        return false;
685→    }
686→    
687→    // NTC_FAULT_HOT (1) = thermistor shorted/stuck low - unsafe to charge
688→    if (pData->status.ntcFault == NTC_FAULT_HOT) {
689→        // Battery might be present but thermistor is faulty
690→        // Check voltage to confirm battery presence
691→        return !pData->status.vsysStat;  // Battery present if voltage > 3.0V
692→    }
693→    
694→    // Normal thermistor reading - battery is present
695→    return true;
696→}
697→
698→void BQ24297_UpdateBatteryStatus(void) {
699→    bool oldBatPresent = pData->status.batPresent;
700→    bool oldChargeAllowed = pData->chargeAllowed;
701→
702→    pData->status.batPresent = BQ24297_IsBatteryPresent();
703→    pData->chargeAllowed = pData->status.batPresent &&
704→                           (pData->status.ntcFault != NTC_FAULT_HOT);
705→
706→    // Enforce charge state via I2C when chargeAllowed changes
707→    if (pData->chargeAllowed != oldChargeAllowed) {
708→        BQ24297_ChargeEnable(pData->chargeAllowed);
709→        LOG_D("BQ24297: Charging %s",
710→              pData->chargeAllowed ? "enabled" : "disabled");
711→    }
712→
713→    if (oldBatPresent != pData->status.batPresent) {
714→        LOG_D("BQ24297: Battery %s",
715→              pData->status.batPresent ? "detected" : "not detected");
716→    }
717→}
718→
719→void BQ24297_SetPowerMode(bool externalPowerPresent) {
720→    static bool lastExternalPowerState = false;
721→    static bool initialized = false;
722→
723→    // Only log when state actually changes
724→    if (!initialized || lastExternalPowerState != externalPowerPresent) {
725→        if (externalPowerPresent) {
726→            LOG_D("BQ24297_SetPowerMode: External power detected");
727→        } else {
728→            LOG_D("BQ24297_SetPowerMode: Battery power only");
729→        }
730→        lastExternalPowerState = externalPowerPresent;
731→        initialized = true;
732→    }
733→
734→    // OTG mode is disabled by default in the BQ24297 and set to disabled at init.
735→    // Charging is always enabled and handled autonomously by the hardware.
736→    // No action needed here - just logging state changes above.
737→}
