    force_bootloader_flag = FORCE_BOOTLOADER_FLAG_VALUE; // magic force boot value!

    vTaskDelay(10); // Be sure all operations are finished

    RCON_SoftwareReset();
    return SCPI_RES_ERR; // If we get here, the reset didn't work
}

